import React, { useEffect, useState} from 'react'


const MyBookings = () => {

    const [outputArr,setOutputArr]=useState([]);
    const viewBookings = async () => {
        try {
            //get user info first
            const res = await fetch('/getUser', {
                method: "GET",
                headers: {
                    Accept: "application/json",
                    "Content-Type": "application/json",

                },
                credentials: "include"
            });

            const data = await res.json();

            // retrieving all bookings of current user
            const { email } = data;
            
            const response=await fetch('/showBookings',{
                method:"GET",
                headers: {
                    Accept: "application/json",
                    "Content-Type": "application/json",
                    "X-User-email":email
                },
                
            });
            
            const output=await response.json();
            setOutputArr=output.services
            // console.log(outputArr);

        } catch (error) {
            console.log(error);
        }

    }

    useEffect(() => {
        viewBookings();
    }, [])


    return (
        <div className='flex justify-center items-center text-white text-3xl h-screen '>
        {
          outputArr.length===0?<p>No Data</p>:<p>Data found</p>
        }
        </div>
    )
}

export default MyBookings
